SELECT
    b.channel_id,
    b.channel_title,
    b.brand1,
    b.brand2,
    b.brand3,
    b.video_id,
    b.views,
    b.likes,
    b.comments,
    b.channel_cost,
    b.publishDate,
    b.cpv,
    b.title
