-- ============================================================
-- [요청 2] 크리에이터 상세 통계
-- 목적: 크리에이터 성과 분석
-- ============================================================
SELECT
    ys.channel_id,
    ys.average_views,
    ys.average_views_ads,
    ys.average_views_except_short,
    ys.average_views_short,
    ys.engagement_rate,
    ys.engagement_rate_last_10,
    ys.subs_growth_3_months,
    ys.subs_growth_3_months_amount,
    ys.short_ratio,
    ys.total_videos,
    ys.trend_count,
    ys.format1_long,
    ys.format1_short,
    ys.topic1_long,
    ys.topic1_short,
    ys.topic2_long,
