-- ============================================================
-- [요청 4] 브랜드 기본 정보 (뷰티 관련)
-- 목적: 경쟁사 프로필
-- topic 컬럼 값이 실제와 다르면 조건 수정 필요
-- ============================================================
SELECT
    bl.brand_logo_id,
    bl.brand_name_kr,
    bl.brand_name_en,
    bl.brand_videos,
    bl.avg_views,
    bl.one_month,
    bl.topic,
    bl.related_brands
FROM brand_logo bl
WHERE bl.topic LIKE '%beauty%'
   OR bl.topic LIKE '%makeup%'
   OR bl.topic LIKE '%cosmetic%'
   OR bl.topic LIKE '%뷰티%'
   OR bl.topic LIKE '%메이크업%'
   OR bl.topic LIKE '%화장%';


-- ============================================================
-- [요청 5] 크리에이터 프로필 정보
-- 목적: 구독자 수, 썸네일, 비용 등 크리에이터 카드 표시
-- 저장: youtuber_info.csv
-- ============================================================
SELECT
    yi.channel_id,
    yi.title,
    yi.subscribers,
    yi.totalViews,
    yi.totalVideos,
    yi.thumbnail,
    yi.categories,
    yi.channel_type,
    yi.Main_tag1,
    yi.Main_tag2,
    yi.email,
    yi.channel_cost,
