-- ============================================================
-- [요청 6] 크리에이터 성장성/신뢰도 지표
-- 목적: 성장률, 감성분석, 위기감 조성 핵심 데이터
-- 저장: data_mining.csv
-- ============================================================
SELECT
    dm.channel_id,
    dm.engagement_rate,
    dm.engagement_rate_ad_o,
    dm.engagement_rate_ad_x,
    dm.avg_subs_increment_rate,
    dm.avg_views_increment_rate,
    dm.Reactivity,
    dm.Reliability,
    dm.Scalability,
    dm.sentiment_category,
    dm.sentiment_prop,
