-- ============================================================
-- [요청 7] 네이버 검색 트렌드 (릴리바이레드 vs 경쟁사)
-- 목적: 시장 내 검색량 비교, 트렌드 시각화
-- 저장: naver_trend.csv
-- ============================================================
SELECT
    nw.keyword,
    nw.rank,
    nw.week_start_date,
    nw.week_end_date,
    nw.category_id
FROM naver_weekly_trend_rank nw
WHERE nw.keyword IN ('릴리바이레드', '에뛰드', '클리오', '페리페라',
    '웨이크메이크', '롬앤', '데이지크', '어뮤즈', '에스쁘아', '퓌');


-- ============================================================
-- [요청 8] 올리브영 브랜드 스코어 추이
-- 목적: 브랜드 점수 변동 시각화, 경쟁사 비교
-- 저장: oliveyoung_brand_score.csv
-- ============================================================
SELECT
    obs.brand,
    obs.brand_score,
    obs.brand_rank_score,
    obs.brand_related_video_score,
    obs.date
FROM oliveyoung_brand_score obs
WHERE obs.brand IN (836, 81, 84, 239, 103, 4302, 83, 978, 117, 328, 3174, 63, 107, 46, 314);


-- ============================================================
-- [요청 9] 올리브영 제품 순위 변동
-- 목적: 제품별 일별 순위 추이, 위기감 핵심 차트
-- 저장: oliveyoung_product_rank.csv
-- ============================================================
SELECT
    opr.product_id,
    opr.category,
    opr.rank,
    opr.score,
    opr.date,
    opr.momentum_direction,
    opr.rank_avg_7d
FROM oliveyoung_product_agg_rank_daily opr
WHERE opr.product_id IN (
    SELECT opi.product_id
    FROM oliveyoung_product_info opi
    WHERE opi.brand IN ('릴리바이레드', '에뛰드', '클리오', '페리페라',
        '웨이크메이크', '롬앤', '데이지크', '어뮤즈', '에스쁘아', '퓌')
);


-- ============================================================
-- [요청 10] 올리브영 제품 정보
-- 목적: 제품명, 카테고리 매핑
-- 저장: oliveyoung_product_info.csv
-- ============================================================
SELECT
    opi.product_id,
    opi.brand,
    opi.product,
    opi.category,
    opi.image
FROM oliveyoung_product_info opi
WHERE opi.brand IN ('릴리바이레드', '에뛰드', '클리오', '페리페라',
    '웨이크메이크', '롬앤', '데이지크', '어뮤즈', '에스쁘아', '퓌');
